# input
r, c = map(int, input().split())

cake = [list(input()) for _ in range(r)]

# dfs
def dfs(i, j):
    if i < 0 or i >= r or j < 0 or j >= c or cake[i][j] == ".":
        return 0
    cake[i][j] = "."
    return 1 + dfs(i + 1, j) + dfs(i - 1, j) + dfs(i, j + 1) + dfs(i, j - 1)

# output
print(max([dfs(i, j) for i in range(r) for j in range(c)]))


